import React, { useState, useEffect } from 'react';
import Login from './pages/Login';
import StudentHome from './pages/StudentHome';
import AddProject from './pages/AddProject';
import AdminDashboard from './pages/AdminDashboard';
// Import ProjectDetails if you have it created

function App() {
  const [currentPage, setCurrentPage] = useState('login');
  const [user, setUser] = useState(null);
  const [selectedProject, setSelectedProject] = useState(null);

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('user_info');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      setCurrentPage('home');
    }
  }, []);

  const handleLogin = (userData) => {
    setUser(userData);
    setCurrentPage('home');
  };

  const handleLogout = () => {
    localStorage.removeItem('user_info');
    setUser(null);
    setCurrentPage('login');
  };

  return (
    <div className="App">
      {currentPage === 'login' && <Login onLogin={handleLogin} />}
      
      {currentPage === 'home' && (
        <StudentHome 
          onNavigate={(page) => setCurrentPage(page)} 
          onViewProject={(project) => {
            setSelectedProject(project);
            setCurrentPage('details');
          }}
          onLogout={handleLogout}
        />
      )}

      {currentPage === 'add-project' && (
        <AddProject onNavigate={(page) => setCurrentPage(page)} />
      )}

      {currentPage === 'admin' && (
        <AdminDashboard onNavigate={(page) => setCurrentPage(page)} />
      )}
      
      {/* If you have a details page, add it here */}
      {currentPage === 'details' && (
         <div className="bg-[#0a0a0a] min-h-screen text-white p-10">
            <button onClick={() => setCurrentPage('home')} className="mb-4 text-indigo-400">← Back</button>
            <h1 className="text-4xl font-bold">{selectedProject?.title}</h1>
            <p className="mt-4 text-gray-400">{selectedProject?.description}</p>
            {/* Add more details as needed */}
         </div>
      )}
    </div>
  );
}

export default App;
